288	\subsection{Comparison with the \(\Ext\) contravariant sequence}
289	
290	The following four lemmas bridge the biproduct structure on the abelian-group side with the \(\Ext\) biproduct additivity, preparing the comparison isomorphism.
291	
292	\begin{lemma}\leanok
293	[Elementwise formula for \(\toBiprod\)]
294	  \label{lem:Scheme_HModule_prime_toBiprod_apply}
295	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod_apply}
296	  
297	  For \(y \in H^{\prime n}(X_4, \mathcal F)\),
298	  \[
299	    \toBiprod(y) \;=\; \bigl(\mathrm{restriction}_{X_4 \to X_2}(y),\; \mathrm{restriction}_{X_4 \to X_3}(y)\bigr).
300	  \]
301	\end{lemma}
302	
303	\begin{proof}
304	  
305	  \leanok
306	  Follows from the definition of \(\toBiprod\) as a biproduct lift and the naturality of the biproduct isomorphism with the product.
307	\end{proof}
308	
309	\begin{lemma}\leanok
310	[Elementwise formula for \(\fromBiprod\)]
311	  \label{lem:Scheme_HModule_prime_fromBiprod_biprodIsoProd_inv_apply}
312	  \lean{AlgebraicGeometry.Scheme.HModule'_fromBiprod_biprodIsoProd_inv_apply}
313	  
314	  For \(y_2 \in H^{\prime n}(X_2, \mathcal F)\) and \(y_3 \in H^{\prime n}(X_3, \mathcal F)\),
315	  \[
316	    \fromBiprod(y_2, y_3) \;=\; \mathrm{restriction}_{X_2 \to X_1}(y_2) \;-\; \mathrm{restriction}_{X_3 \to X_1}(y_3).
317	  \]
318	\end{lemma}
319	
320	\begin{proof}
