926	\subsection{Affine Čech-acyclic cover carrier}
927	
928	The predicate \(\IsAffineHModuleVanishing\) (Definition~REF) requires vanishing on every affine open. To instantiate it from Čech data, we introduce a carrier class that bundles the existence of a suitable cover per affine open.
929	
930	\begin{definition}\leanok
931	[Affine Čech-acyclic cover carrier]
932	  \label{def:Scheme_HasAffineCechAcyclicCover}
933	  \lean{AlgebraicGeometry.Scheme.HasAffineCechAcyclicCover}
934	  
935	  For every affine open \(U\), there exists an indexed cover \(\mathfrak U\) with \(\bigsqcup \mathfrak U_i = U\) that is Čech-acyclic and carries a comparison isomorphism.
936	\end{definition}
937	
938	\begin{theorem}\leanok
939	[Producer for \(\IsAffineHModuleVanishing\)]
940	  \label{thm:Scheme_instIsAffineHModuleVanishing_of_hasAffineCechAcyclicCover}
941	  \lean{AlgebraicGeometry.Scheme.instIsAffineHModuleVanishing_of_hasAffineCechAcyclicCover}
942	  
943	  If \(\HasAffineCechAcyclicCover\) holds, then \(\IsAffineHModuleVanishing\) holds.
944	\end{theorem}
945	
946	\begin{proof}
947	
948	
949	\leanok
950	  Per affine \(U\), extract the cover from the carrier, register the acyclicity and comparison instances, and apply the rewrite-bridge.
951	\end{proof}
